function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const adj = new Array(n).fill(0).map(() => []);
    const in_degree = new Array(n).fill(0);

    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
        in_degree[v]++;
    }

    const queue: number[] = [];
    for (let i = 0; i < n; i++) {
        if (in_degree[i] === 0) {
            queue.push(i);
        }
    }

    const topologicalOrder: number[] = [];
    while (queue.length > 0) {
        const u = queue.shift()!;
        topologicalOrder.push(u);
        for (const [v, cost] of adj[u]) {
            in_degree[v]--;
            if (in_degree[v] === 0) {
                queue.push(v);
            }
        }
    }

    let maxEdge = 0;
    for (const [u, v, cost] of edges) {
        if (cost > maxEdge) {
            maxEdge = cost;
        }
    }

    let low = 0;
    let high = maxEdge;
    let answer = -1;

    function isFeasible(x: number): boolean {
        const dist = new Array(n).fill(Infinity);
        dist[0] = 0;
        for (const u of topologicalOrder) {
            if (!online[u]) continue;
            for (const [v, cost] of adj[u]) {
                if (cost < x) continue;
                if (!online[v]) continue;
                if (dist[u] + cost < dist[v]) {
                    dist[v] = dist[u] + cost;
                }
            }
        }
        return dist[n - 1] <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (isFeasible(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}

